package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testWithDelimiter() {
        // Given
        char delimiter = ',';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newCsvFormat = csvFormat.withDelimiter(delimiter);

        // Then
        assertNotSame(csvFormat, newCsvFormat);
        assertEquals(delimiter, newCsvFormat.getDelimiter());
    }

    @Test
    public void testWithDelimiter_LineBreak() {
        // Given
        char delimiter = '\n';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When & Then
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            csvFormat.withDelimiter(delimiter);
        });
        assertEquals("The delimiter cannot be a line break", exception.getMessage());
    }

